import { NextResponse } from "next/server";

export async function POST(req: Request) {
  try {
    const body = await req.json();

    // Simulate n8n webhook delay (e.g. 3 seconds)
    await new Promise((resolve) => setTimeout(resolve, 3000));

    // For MVP, we will return a hardcoded/mock markdown string.
    // In the real app, we will fetch from the n8n Webhook here and return its response.

    let sampleContent = `
# Ceramah: ${body.topic || "Pentingnya Menjaga Lisan"}

**Assalamu'alaikum warahmatullahi wabarakatuh.**

Alhamdulillah, segala puji bagi Allah SWT Tuhan semesta alam. Shalawat serta salam senantiasa kita haturkan kepada baginda Nabi Muhammad SAW beserta keluarga, sahabat, dan umatnya yang istiqamah hingga akhir zaman.

### Pendahuluan
Hadirin sekalian yang dirahmati Allah,
Pada kesempatan yang berbahagia ini, mari kita merenungkan tentang pentingnya menjaga lisan. Terutama di era media sosial saat ini, lisan kita tidak hanya berupa ucapan dari mulut, melainkan juga jempol dan ketikan jari kita di dunia maya.

### Dalil Al-Quran
Allah SWT berfirman dalam Surah Qaf ayat 18:

مَّا يَلْفِظُ مِن قَوْلٍ إِلَّا لَدَيْهِ رَقِيبٌ عَتِيدٌ

*"Tiada suatu ucapanpun yang diucapkannya melainkan ada di dekatnya malaikat pengawas yang selalu hadir."* (QS. Qaf: 18)

### Dalil Hadits
Rasulullah SAW juga bersabda dalam sebuah hadits yang diriwayatkan oleh Imam Bukhari dan Muslim:

مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ

*"Barangsiapa beriman kepada Allah dan hari akhir, hendaklah ia berkata baik atau diam."* (HR. Bukhari dan Muslim)

### Inti Nasihat
Gaya bahasa yang Anda pilih adalah **${body.tone}** untuk audiens **${body.audience}**.
*(Ini adalah simulasi teks. Pada versi final, n8n akan menggenerasikan teks ceramah yang panjangnya sesuai durasi: **${body.duration}** dengan tone dan struktur yang tepat.)*

Semoga kita semua bisa menjadi hamba-Nya yang selalu menjaga lisan dari perkataan dusta, ghibah, maupun fitnah. Aamiin ya Rabbal 'Alamin.

**Wassalamu'alaikum warahmatullahi wabarakatuh.**
    `;

    // Special formatting for Khotbah Jumat
    if (body.type === "khotbah_jumat") {
        sampleContent = `
# Khotbah Jumat: ${body.topic || "Menjaga Iman di Zaman Fitnah"}

## Khotbah Pertama

**Assalamu'alaikum warahmatullahi wabarakatuh.**

إِنَّ الْحَمْدَ لِلَّهِ، نَحْمَدُهُ وَنَسْتَعِيْنُهُ وَنَسْتَغْفِرُهُ، وَنَعُوْذُ بِاللَّهِ مِنْ شُرُوْرِ أَنْفُسِنَا...

Hadirin jamaah Jumat yang dimuliakan Allah,
Khatib berwasiat kepada diri khatib pribadi dan jamaah sekalian, marilah kita senantiasa meningkatkan ketakwaan kita kepada Allah SWT...

*(...Isi khotbah pertama sesuai topik ${body.topic} dengan gaya ${body.tone} dipaparkan di sini...)*

بَارَكَ اللهُ لِي وَلَكُمْ فِي الْقُرْآنِ الْعَظِيْمِ...

---

## Khotbah Kedua

الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ، وَأَشْهَدُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَلِيُّ الصَّالِحِينَ...

Hadirin yang berbahagia, di khotbah kedua ini mari kita menundukkan kepala dan berdoa:

اَللَّهُمَّ اغْفِرْ لِلْمُسْلِمِيْنَ وَالْمُسْلِمَاتِ، وَالْمُؤْمِنِيْنَ وَالْمُؤْمِنَاتِ...
*(Ya Allah, ampunilah dosa kaum muslimin dan muslimat, mukminin dan mukminat...)*

**Wassalamu'alaikum warahmatullahi wabarakatuh.**
        `;
    }

    return NextResponse.json({
      content: sampleContent,
      success: true
    });

  } catch (error) {
    return NextResponse.json({ error: "Gagal memproses" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";

export async function GET() {
  try {
    // Simulate slight delay
    await new Promise((resolve) => setTimeout(resolve, 800));

    // Mock realistic AI-generated topical ideas
    const topicIdeas = [
      "Menjaga Lisan dan Etika di Era Media Sosial",
      "Keutamaan Istighfar di Kala Sempit dan Lapang",
      "Sabar Menghadapi Resesi dan Ujian Ekonomi",
      "Mendidik Anak Generasi Alpha dengan Akhlakul Karimah",
      "Bahaya Hasad dan Penyakit Hati dalam Bertetangga"
    ];

    // Shuffle and pick 3 topics
    const shuffled = topicIdeas.sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, 3);

    return NextResponse.json({
      topics: selected,
    });
  } catch (error) {
    return NextResponse.json({ error: "Gagal menyarankan topik" }, { status: 500 });
  }
}

"use client";

import { useState } from "react";
import { Sparkles, MessageCircle, Clock, Users, BookOpen, ToggleLeft, ToggleRight, Loader2 } from "lucide-react";

const TYPES = [
  { id: "khotbah_jumat", label: "Khotbah Jumat" },
  { id: "kultum", label: "Kultum" },
  { id: "pengajian_rutin", label: "Pengajian Rutin" },
  { id: "tausiyah_kematian", label: "Tausiyah Kematian" },
  { id: "ceramah_hari_raya", label: "Ceramah Hari Raya" },
  { id: "kajian_keluarga", label: "Kajian Keluarga/Nikah" },
];

const AUDIENCES = [
  { id: "umum", label: "Jamaah Umum / Masyarakat Masjid", desc: "Campuran berbagai usia, profesi. Bahasa sederhana, tema universal (syukur, sabar, shalat)." },
  { id: "milenial", label: "Anak Muda (Milenial / Gen Z)", desc: "Bahasa relatable, relevan dengan tren (sosmed, mental health), tidak menggurui." },
  { id: "ibu-ibu", label: "Ibu-ibu / Majelis Taklim", desc: "Seputar keluarga, mendidik anak, fiqih wanita. Interaktif dan emosional." },
  { id: "profesional", label: "Pekerja / Profesional", desc: "Audiens sibuk. Materi aplikatif kerja (etos kerja, rezeki halal, manajemen stres)." },
  { id: "keluarga", label: "Keluarga / Calon Pasangan", desc: "Fokus manajemen konflik rumah tangga, hak kewajiban suami istri, parenting." },
  { id: "anak-anak", label: "Pelajar / Anak-anak", desc: "Bahasa sangat sederhana, banyak ilustrasi, cerita, dan interaksi/kuis." },
];

const TONES = [
  { id: "menggugah", label: "Menggugah & Semangat" },
  { id: "lembut", label: "Lembut & Menyentuh" },
  { id: "logis", label: "Logis & Akademis" },
  { id: "santai", label: "Santai & Humoris" },
  { id: "tegas", label: "Tegas (Peringatan)" },
  { id: "bercerita", label: "Bercerita (Storytelling)" },
];

const DURATIONS = [
  { id: "singkat", label: "5-7 Menit" },
  { id: "sedang", label: "15 Menit" },
  { id: "panjang", label: "30+ Menit" },
];

interface SermonFormProps {
  onGenerated: (result: string) => void;
  isLoading: boolean;
  setIsLoading: (loading: boolean) => void;
}

export default function SermonForm({ onGenerated, isLoading, setIsLoading }: SermonFormProps) {
  const [topic, setTopic] = useState("");
  const [selectedType, setSelectedType] = useState("khotbah_jumat");
  const [selectedAudience, setSelectedAudience] = useState("umum");
  const [selectedTone, setSelectedTone] = useState("menggugah");
  const [selectedDuration, setSelectedDuration] = useState("sedang");
  const [requireDalil, setRequireDalil] = useState(true);

  const [isSuggesting, setIsSuggesting] = useState(false);

  const handleSuggestTopic = async () => {
    setIsSuggesting(true);
    try {
      const res = await fetch("/api/topics");
      const data = await res.json();
      if (data.topics && data.topics.length > 0) {
        setTopic(data.topics[0]); 
        // In a real app we'd show a modal or dropdown with multiple choices
      }
    } catch (error) {
      console.error("Failed to fetch topics", error);
    } finally {
      setIsSuggesting(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      const res = await fetch("/api/generate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          topic: topic || "Pentingnya Menjaga Lisan", // Fallback if empty
          type: selectedType,
          audience: selectedAudience,
          tone: selectedTone,
          duration: selectedDuration,
          requireDalil,
        }),
      });

      const data = await res.json();
      if (data.content) {
        onGenerated(data.content);
      }
    } catch (error) {
      console.error("Failed to generate sermon", error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden text-gray-800">
      <div className="p-5 sm:p-6 pb-4 border-b border-gray-100 dark:border-slate-800 bg-emerald-50/50 dark:bg-slate-900/50">
        <h2 className="text-xl font-bold font-serif text-emerald-900 dark:text-emerald-50">Mulai Generate</h2>
        <p className="text-sm text-emerald-700 dark:text-emerald-400 mt-1 opacity-80">Sesuaikan preferensi ceramah Anda</p>
      </div>

      <form onSubmit={handleSubmit} className="p-5 sm:p-6 space-y-6 bg-white dark:bg-slate-900">
        {/* Topic Input */}
        <div className="space-y-3">
          <label className="block text-sm font-semibold text-gray-700 dark:text-gray-200">Topik atau Tema</label>
          <div className="flex gap-2 flex-col sm:flex-row">
            <input
              type="text"
              placeholder="Contoh: Sabar dalam menghadapi cobaan..."
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
              className="flex-1 w-full border border-gray-200 dark:border-slate-700 dark:bg-slate-800 dark:text-white rounded-xl px-4 py-3 text-base focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-all outline-none placeholder:text-gray-400 dark:placeholder:text-gray-500"
            />
            <div className="flex flex-col gap-1">
              <button
                type="button"
                onClick={handleSuggestTopic}
                disabled={isSuggesting}
                className="px-4 py-3 h-full bg-emerald-50/80 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-400 hover:bg-emerald-100 dark:hover:bg-emerald-800/40 font-medium rounded-xl flex items-center justify-center gap-2 transition-colors disabled:opacity-50 border border-emerald-100 dark:border-emerald-800/30 whitespace-nowrap"
              >
                {isSuggesting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                <span>Bantu Cari Topik</span>
              </button>
            </div>
          </div>
          <p className="text-[11px] text-gray-500 dark:text-gray-400 mt-1 pl-1">Klik tombol di samping untuk mendapatkan ide topik otomatis</p>
        </div>

        {/* Jenis Ceramah */}
        <div className="space-y-3">
          <label className="flex items-center gap-2 text-sm font-semibold text-gray-700 dark:text-gray-200">
            <BookOpen className="w-4 h-4 text-emerald-600 dark:text-emerald-500" /> Jenis Ceramah
          </label>
          <div className="flex flex-wrap gap-2">
            {TYPES.map((t) => (
              <button
                key={t.id}
                type="button"
                onClick={() => setSelectedType(t.id)}
                className={`px-3 py-2 rounded-xl text-sm font-medium transition-all ${
                  selectedType === t.id
                    ? "bg-emerald-600 text-white shadow-md shadow-emerald-200 dark:shadow-none"
                    : "bg-gray-50 dark:bg-slate-800 text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-slate-700 border border-gray-200/60 dark:border-slate-700"
                }`}
              >
                {t.label}
              </button>
            ))}
          </div>
        </div>

        {/* Target Audiens */}
        <div className="space-y-3">
          <label className="flex items-center gap-2 text-sm font-semibold text-gray-700 dark:text-gray-200">
            <Users className="w-4 h-4 text-emerald-600 dark:text-emerald-500" /> Target Audiens
          </label>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
            {AUDIENCES.map((a) => (
               <button
               key={a.id}
               type="button"
               onClick={() => setSelectedAudience(a.id)}
               className={`text-left p-3 rounded-xl transition-all border ${
                 selectedAudience === a.id
                   ? "bg-emerald-50/50 dark:bg-emerald-900/20 border-emerald-300 dark:border-emerald-700 shadow-sm"
                   : "bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 hover:bg-gray-50 dark:hover:bg-slate-700/50"
               }`}
             >
               <div className={`text-sm font-bold ${selectedAudience === a.id ? "text-emerald-800 dark:text-emerald-400" : "text-gray-700 dark:text-gray-200"}`}>
                 {a.label}
               </div>
               <div className={`text-[11px] mt-1 line-clamp-2 ${selectedAudience === a.id ? "text-emerald-600/80 dark:text-emerald-400/80" : "text-gray-500 dark:text-gray-400"}`}>
                 {a.desc}
               </div>
             </button>
            ))}
          </div>
        </div>

        {/* Tone/Gaya & Durasi */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-2">
          <div className="space-y-3">
            <label className="flex items-center gap-2 text-sm font-semibold text-gray-700 dark:text-gray-200">
              <MessageCircle className="w-4 h-4 text-emerald-600 dark:text-emerald-500" /> Gaya Bahasa
            </label>
            <div className="flex flex-wrap gap-2">
              {TONES.map((t) => (
                <button
                  key={t.id}
                  type="button"
                  onClick={() => setSelectedTone(t.id)}
                  className={`px-3 py-2 rounded-lg text-sm transition-all ${
                    selectedTone === t.id
                      ? "bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 border-blue-200 dark:border-blue-800 border font-medium"
                      : "bg-gray-50 dark:bg-slate-800 text-gray-600 dark:text-gray-300 border border-gray-100 dark:border-slate-700 hover:bg-gray-100 dark:hover:bg-slate-700"
                  }`}
                >
                  {t.label}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-3">
            <label className="flex items-center gap-2 text-sm font-semibold text-gray-700 dark:text-gray-200">
              <Clock className="w-4 h-4 text-emerald-600 dark:text-emerald-500" /> Durasi
            </label>
            <div className="flex bg-gray-100 dark:bg-slate-800 p-1 rounded-xl">
              {DURATIONS.map((d) => (
                <button
                  key={d.id}
                  type="button"
                  onClick={() => setSelectedDuration(d.id)}
                  className={`flex-1 py-2 px-1 text-xs sm:text-sm font-medium rounded-lg transition-all ${
                    selectedDuration === d.id
                      ? "bg-white dark:bg-slate-600 text-gray-900 dark:text-white shadow-sm"
                      : "text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300"
                  }`}
                >
                  {d.label}
                </button>
              ))}
            </div>
          </div>
        </div>

        <hr className="border-gray-100 dark:border-slate-800" />

        {/* Dalil Toggle */}
        <div className="flex items-center justify-between bg-gray-50/50 dark:bg-slate-800/50 p-4 rounded-xl border border-gray-100 dark:border-slate-700/50">
          <div>
             <h4 className="text-sm font-bold text-gray-800 dark:text-gray-200">Sertakan Dalil Sahih</h4>
             <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">Ayat Al-Quran & Hadits (min. Hasan)</p>
          </div>
          <button 
            type="button" 
            onClick={() => setRequireDalil(!requireDalil)}
            role="switch"
            aria-checked={requireDalil}
            className={`relative inline-flex h-8 w-14 shrink-0 cursor-pointer items-center justify-center rounded-full transition-colors duration-200 ease-in-out focus:outline-none focus-visible:ring-2 focus-visible:ring-emerald-500 focus-visible:ring-offset-2 ${
              requireDalil ? "bg-emerald-500" : "bg-gray-200 dark:bg-slate-600"
            }`}
          >
            <span className="sr-only">Toggle Dalil Sahih</span>
            <span
              className={`pointer-events-none inline-block h-6 w-6 transform rounded-full bg-white shadow-sm ring-0 transition duration-200 ease-in-out flex items-center justify-center ${
                requireDalil ? "translate-x-3" : "-translate-x-3"
              }`}
            >
              {requireDalil && <Sparkles className="w-3.5 h-3.5 text-emerald-500" />}
            </span>
          </button>
        </div>

        {/* Submit */}
        <button
          type="submit"
          disabled={isLoading}
          className="w-full py-4 px-6 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-2xl transition-all shadow-lg shadow-emerald-200 dark:shadow-emerald-900/20 disabled:opacity-70 disabled:cursor-not-allowed flex justify-center items-center gap-2 mt-4 text-lg border-b-4 border-emerald-800 active:border-b-0 active:translate-y-1"
        >
          {isLoading ? (
            <>
              <Loader2 className="w-5 h-5 animate-spin" />
              Meracik Ceramah...
            </>
          ) : (
            "Generate Ceramah Sekarang"
          )}
        </button>
      </form>
    </div>
  );
}

import ReactMarkdown from "react-markdown";
import { Copy, Download, Share2, Check } from "lucide-react";
import { useState } from "react";

interface SermonResultProps {
  content: string;
}

export default function SermonResult({ content }: SermonResultProps) {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  if (!content) return null;

  return (
    <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-md border border-gray-100 dark:border-slate-800 overflow-hidden text-gray-800 dark:text-gray-100 transition-all duration-500 animate-in fade-in slide-in-from-bottom-4">
      {/* Result Header */}
      <div className="p-4 sm:p-5 pb-3 border-b border-gray-100 dark:border-slate-800 flex justify-between items-center bg-gray-50/80 dark:bg-slate-900/80 sticky top-0 z-10 backdrop-blur-sm">
        <div>
          <h2 className="text-lg font-bold font-serif text-gray-800 dark:text-gray-100">Teks Ceramah Selesai</h2>
          <p className="text-xs text-emerald-600 dark:text-emerald-400 font-medium mt-0.5">Siap dibaca atau disimpan.</p>
        </div>
        <div className="flex gap-1.5 sm:gap-2">
          <button
            onClick={handleCopy}
            className="p-2 sm:px-3 sm:py-2 text-sm text-gray-600 dark:text-gray-300 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:bg-gray-50 dark:hover:bg-slate-700 rounded-lg flex items-center justify-center gap-2 transition-all tooltip tooltip-bottom"
            title="Salin Teks"
          >
            {copied ? <Check className="w-4 h-4 text-emerald-500 dark:text-emerald-400" /> : <Copy className="w-4 h-4" />}
            <span className="hidden sm:inline font-medium">{copied ? "Tersalin" : "Salin"}</span>
          </button>

          <button className="p-2 sm:px-3 sm:py-2 text-sm text-gray-600 dark:text-gray-300 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:bg-gray-50 dark:hover:bg-slate-700 rounded-lg flex items-center justify-center gap-2 transition-all">
            <Download className="w-4 h-4" />
            <span className="hidden sm:inline font-medium">PDF</span>
          </button>
        </div>
      </div>

      {/* Result Body (Markdown) */}
      <div className="p-5 sm:p-8 bg-white dark:bg-slate-900 selection:bg-emerald-100 dark:selection:bg-emerald-900/30 min-h-[40vh] max-h-[70vh] overflow-y-auto w-full prose prose-emerald dark:prose-invert prose-p:leading-relaxed prose-headings:font-serif prose-headings:text-gray-900 dark:prose-headings:text-gray-100 prose-a:text-emerald-600 dark:prose-a:text-emerald-400">
        <ReactMarkdown>{content}</ReactMarkdown>
      </div>

      {/* Footer Info */}
      <div className="px-5 py-3 sm:px-8 border-t border-gray-100 dark:border-slate-800 bg-gray-50 dark:bg-slate-800/50 text-xs text-gray-500 dark:text-gray-400 text-center">
        Disusun oleh MimbarPro MVP
      </div>
    </div>
  );
}

